const rawText = $input.first().json.output;

// Entfernt eventuelle Markdown-Codeblock-Marker, falls Gemini sie trotzdem einbaut
const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

const parsed = JSON.parse(cleaned);

return { json: parsed };

const webhookData = $('Zutaten-Eingang (Angular)').first().json;
const headers = webhookData.headers;

const clientIp = 
  headers['x-forwarded-for']?.split(',')[0].trim() ||
  headers['x-real-ip'] ||
  webhookData.ip ||
  '127.0.0.1';

// Firebase erlaubt keine Punkte in Keys - IPv4 (und ":" bei IPv6) ersetzen
const safeIp = clientIp.replace(/\./g, '_').replace(/:/g, '_');

const quotaData = $input.first().json;

const ipCount = quotaData[safeIp] || 0;
const totalCount = quotaData['_total'] || 0;

const IP_LIMIT = 3;
const TOTAL_LIMIT = 12;

const ipLimitReached = ipCount >= IP_LIMIT;
const totalLimitReached = totalCount >= TOTAL_LIMIT;
const limitReached = ipLimitReached || totalLimitReached;

return {
  json: {
    ...webhookData,
    clientIp,
    safeIp,
    ipCount,
    totalCount,
    limitReached,
    limitReason: ipLimitReached 
      ? 'Du hast dein Tageslimit von 3 Rezepten erreicht.' 
      : totalLimitReached 
        ? 'Das System-weite Tageslimit ist erreicht. Bitte versuche es morgen erneut.' 
        : null
  }
};

